from collections import Counter

def get_lemmas(text):
    if not text:
        return ""
    # 1. Разбиваем текст на отдельные слова
    words = text.split()

    # 2. Получаем нормальную форму (лемму) для каждого слова
    # Берем первый вариант разбора [0], так как он наиболее вероятен
    lemmas = [morph.parse(word)[0].normal_form for word in words]

    # 3. Соединяем леммы обратно в строку через пробел
    return " ".join(lemmas)

