def get_top_20(series):
    all_words = " ".join(series.dropna().astype(str)).split()
    return Counter(all_words).most_common(20)

# Подготовка данных
raw_words_list = " ".join(df_final['raw_text'].apply(lambda x: clean_text(x).lower())).split()
