def plot_freq(data, ax, title, palette):
    words, counts = zip(*data)
    sns.barplot(
        x=list(counts),
        y=list(words),
        ax=ax,
        palette=palette,
        hue=words,
        legend=False,
        edgecolor='black',
        linewidth=0.5
    )
    ax.set_title(title, fontsize=18, fontweight='bold', pad=25)
    ax.set_xlabel('Frequency', fontsize=14)
    ax.set_ylabel('', fontsize=14)
    ax.tick_params(labelsize=12)

