from nltk.util import ngrams
import pandas as pd
from collections import Counter

# 1. Функция для подготовки сводной таблицы
def create_freq_df(counts_misha, counts_mira, top_n=30):
    all_keys = set(list(counts_misha.keys()) + list(counts_mira.keys()))
    data = []
    for k in all_keys:
        m_val = counts_misha.get(k, 0)
        w_val = counts_mira.get(k, 0)
        data.append({"Объект": k, "Миша": m_val, "Мира": w_val, "Общее": m_val + w_val})
    return pd.DataFrame(data).sort_values(by="Общее", ascending=False).head(top_n).reset_index(drop=True)

# 2. Сбор данных
misha_data = df_final[df_final['author'] == 'в общем-то миша']['lemmas_clean']
mira_data = df_final[df_final['author'] == 'мир@ кельбур']['lemmas_clean']

# Частоты лемм
counts_lemmas_misha = Counter(" ".join(misha_data.dropna().astype(str)).split())
counts_lemmas_mira = Counter(" ".join(mira_data.dropna().astype(str)).split())

# Частоты биграмм
def get_bigrams_list(text_series):
    bigrams = []
    for text in text_series.dropna().astype(str):
        tokens = text.split()
        if len(tokens) >= 2:
            bigrams.extend([f"{b[0]} {b[1]}" for b in ngrams(tokens, 2)])
    return bigrams

counts_bigrams_misha = Counter(get_bigrams_list(misha_data))
counts_bigrams_mira = Counter(get_bigrams_list(mira_data))

# 3. Вывод таблиц
