def extract_nlp_features_fast(df, text_col='raw_text'):
    all_entities = []
    all_pos = []

    # Получаем исходные тексты
    raw_texts = df[text_col].fillna("").tolist()

    # Применяем функции очистки перед передачей в nlp.pipe
    cleaned_for_nlp_texts = []
    for text in tqdm(raw_texts, desc="Применение очистки для NLP"):
        text_proc = clean_text(text)
        text_proc = normalize_repeats(text_proc)
        text_proc = filter_profanity_simple(text_proc)
        cleaned_for_nlp_texts.append(text_proc)

    # nlp.pipe — самый быстрый способ обработки больших текстов
    for doc in tqdm(nlp.pipe(cleaned_for_nlp_texts, batch_size=512, n_process=1), total=len(cleaned_for_nlp_texts), desc="Оптимизированный NER/POS"):
        # Извлекаем сущности
        all_entities.append([(ent.text, ent.label_) for ent in doc.ents])

        # Извлекаем POS-теги
        all_pos.append(" ".join([token.pos_ for token in doc]))

    df['entities'] = all_entities
    df['pos_tags'] = all_pos
    return df

# Применяем NLP-пайплайн к агрегированным блокам
