import re
from collections import Counter
import pymorphy3 # Добавляем импорт pymorphy3

morph = pymorphy3.MorphAnalyzer() # Инициализируем анализатор здесь

def get_top_entities(df, entity_type=None):
    flat_ents = []
    # Список сущностей, которые нужно пропустить (в нижнем регистре для сравнения)
    skip_list = {'блин', 'мб', 'хз', 'ах', 'гуд мо', 'пхп', 'пхпха', 'пх'}

    for sublist in df['entities']:
        for ent_text, ent_label in sublist:
            # 1. Преобразуем текст сущности в нижний регистр для фильтрации
            ent_text_lower = ent_text.lower()

            # 2. Фильтруем сущности, чтобы в них была хотя бы одна русская буква (уже есть)
            if not re.search(r'[а-яА-ЯёЁ]', ent_text_lower):
                continue # Пропускаем, если нет русских букв

            # 3. Пропускаем сущности из skip_list
            if ent_text_lower in skip_list:
                continue

            # 4. Унифицируем написание (например, "ставрополь" -> "Ставрополь")
            # Для PER, LOC, ORG используем лемматизацию и Title Case
            if ent_label in ['PER', 'LOC', 'ORG']:
                # Лемматизируем сущность, затем применяем Title Case
                canonical_ent_text = morph.parse(ent_text)[0].normal_form.title()
            else:
                canonical_ent_text = ent_text_lower # Для других типов или если Title Case не подходит

            flat_ents.append((canonical_ent_text, ent_label))

    if entity_type:
        # Если указан тип, фильтруем по нему и возвращаем только текст
        flat_ents_filtered_by_type = [ent[0] for ent in flat_ents if ent[1] == entity_type]
        return Counter(flat_ents_filtered_by_type).most_common(30)
    else:
        # Если тип не указан, форматируем текст с типом сущности.
        # Здесь flat_ents уже содержит унифицированный текст.
        formatted_ents = [f"{text} ({label})" for text, label in flat_ents]
        return Counter(formatted_ents).most_common(30)

# После переопределения функции, нужно ее вызвать
print("Топ именованных сущностей (очищенный и унифицированный список):")
for ent, count in get_top_entities(df_block_agg_with_nlp): # Changed df_final to df_block_agg_with_nlp
    print(f"{ent}: {count}")

