from transformers import pipeline
import torch

# Проверяем GPU
device = 0 if torch.cuda.is_available() else -1

# Используем модель, которая специализируется на детекции эмоций (она более чувствительна, чем базовый sentiment)
# cedr - это корпус с размеченными эмоциями (joy, sadness, anger, fear, surprise)
model_name = 'cointegrated/rubert-tiny2-cedr-emotion-detection'

try:
    emotion_analyzer = pipeline(
        'text-classification',
        model=model_name,
        device=device
    )

    print(f"Модель {model_name} успешно загружена.")

    # Функция для маппинга эмоций в стандартные категории
    def map_emotion_to_sentiment(label):
        # rubert-tiny2-cedr выдает: no_emotion, joy, sadness, surprise, fear, anger
        positives = ['joy', 'surprise']
        negatives = ['sadness', 'fear', 'anger']

        if label in positives: return 'POSITIVE'
        if label in negatives: return 'NEGATIVE'
        return 'NEUTRAL'

    print("Начинаю углубленный анализ...")
    raw_results = emotion_analyzer(filtered_cleaned_text, batch_size=32, truncation=True)

    sentiment_results = []
    for i, res in enumerate(raw_results):
        text = filtered_cleaned_text[i]
        label = res['label']
        score = res['score']

        final_label = map_emotion_to_sentiment(label)

        # Дополнительная проверка на сарказм и ключевые слова
        text_low = text.lower()
        if final_label == 'NEUTRAL':
            if any(w in text_low for w in ['умерла', 'сдохла', 'ужас', 'бесит', 'черт']):
                final_label = 'NEGATIVE'
            elif any(w in text_low for w in ['кайф', 'люблю', 'поздравляю', 'ура']):
                final_label = 'POSITIVE'

        sentiment_results.append({
            'text': text,
            'sentiment': final_label,
            'emotion_raw': label,
            'score': score
        })

    sentiment_df = pd.DataFrame(sentiment_results)
    print(f"Обработано {len(sentiment_df)} текстов.")
    display(sentiment_df.head(10))

except Exception as e:
    print(f"Не удалось загрузить модель или провести анализ: {e}")

