"""### Кластеризация текстов с помощью TF-IDF и K-Means"""

from sklearn.feature_extraction.text import TfidfVectorizer
from sklearn.cluster import KMeans
import pandas as pd
import matplotlib.pyplot as plt
import seaborn as sns

sns.set_theme(style="whitegrid")
plt.rcParams['figure.dpi'] = 100

# 1. Подготовка данных: используем очищенные леммы
# Удаляем пустые или NaN значения, так как TfidfVectorizer не может их обработать
texts_for_clustering = df_final[df_final['lemmas_clean'].notna() & (df_final['lemmas_clean'] != '')]['lemmas_clean']

print(f"Количество текстов для кластеризации: {len(texts_for_clustering)}")

# 2. TF-IDF векторизация
# min_df=5 - игнорировать слова, которые встречаются менее чем в 5 документах
# max_df=0.8 - игнорировать слова, которые встречаются более чем в 80% документов (слишком частые слова)
# Добавляем n-граммы (unigrams и bigrams) для улучшения качества признаков
vectorizer = TfidfVectorizer(max_features=5000, min_df=5, max_df=0.8, ngram_range=(1, 2))
tfidf_matrix = vectorizer.fit_transform(texts_for_clustering)

print(f"Размерность TF-IDF матрицы: {tfidf_matrix.shape}")

# 3. K-Means Кластеризация
num_clusters = 7  # Используем то же количество тем, что и для LDA

print(f"Начинаю K-Means кластеризацию с {num_clusters} кластерами...")
kmeans = KMeans(
    n_clusters=num_clusters,
    init='k-means++', # "умный" выбор начальных центроидов
    max_iter=300,
    n_init=10, # количество запусков с разными центроидами
    random_state=42
)
kmeans.fit(tfidf_matrix)

# 4. Присвоение кластеров к DataFrame
# Создаем новый DataFrame, который содержит только те строки, которые использовались для кластеризации
df_clustered = df_final[df_final['lemmas_clean'].notna() & (df_final['lemmas_clean'] != '')].copy()
df_clustered['cluster'] = kmeans.labels_

print("Кластеризация завершена. Присвоены метки кластеров.")
display(df_clustered[['raw_text', 'lemmas_clean', 'cluster']].head())

"""### Характерные слова для каждого кластера"""

# 5. Вывод характерных слов для каждого кластера
print("Топ-10 характерных слов для каждого кластера:")
order_centroids = kmeans.cluster_centers_.argsort()[:, ::-1]
terms = vectorizer.get_feature_names_out()

for i in range(num_clusters):
    print(f"\nКластер {i}:")
    for ind in order_centroids[i, :10]: # Топ-10 слов
        print(f' - {terms[ind]}')

# 6. Визуализация распределения кластеров
plt.figure(figsize=(10, 6))
sns.countplot(x='cluster', data=df_clustered, palette='viridis', hue='cluster', legend=False)
plt.title('Распределение текстов по кластерам', fontsize=16)
plt.xlabel('Номер кластера', fontsize=12)
plt.ylabel('Количество текстов', fontsize=12)
plt.xticks(rotation=0)
plt.show()

